import { navigateToUrl } from 'single-spa';
import { isStandalone } from '../dev/isStandalone';

export type InAppNavigateFn = (to: string, options?: { replace?: boolean }) => void;

function normalizePath(path: string): string {
  const trimmed = (path || '').trim();
  if (!trimmed || trimmed === '#') return '/';
  const withSlash = trimmed.startsWith('/') ? trimmed : `/${trimmed}`;
  if (withSlash.length > 1 && withSlash.endsWith('/')) {
    return withSlash.slice(0, -1);
  }
  return withSlash;
}

/** Shell: single-spa URL bar (giữ domain Linm). Standalone: MemoryRouter navigate. */
export function navigateInAppPath(
  path: string,
  navigate: InAppNavigateFn,
  options?: { replace?: boolean },
): void {
  const normalized = normalizePath(path);
  if (isStandalone) {
    navigate(normalized, { replace: options?.replace });
    return;
  }
  navigateToUrl(normalized);
}

/** Path-only Home target — cấm dùng absolute URL ngoài origin cho in-shell nav. */
export function resolveLinmHomePath(raw?: string): string {
  const configured = (raw ?? import.meta.env.VITE_LINM_SHELL_URL ?? '').trim();
  if (!configured) return '/dashboard';

  if (configured.startsWith('/')) {
    return normalizePath(configured);
  }

  try {
    const parsed = new URL(configured);
    if (typeof window !== 'undefined' && parsed.origin === window.location.origin) {
      return normalizePath(parsed.pathname + parsed.search);
    }
  } catch {
    /* relative path without leading slash */
    return normalizePath(configured);
  }

  return '/dashboard';
}

/** URL app ngoài hiển thị trong iframe (content area) — không đổi domain shell. */
export function resolveExternalContentUrl(raw?: string): string {
  const configured = (raw ?? import.meta.env.VITE_EXTERNAL_CONTENT_URL ?? '').trim();
  return configured;
}

/** Full URL cho site static bên ngoài (linm-home.config.json). */
export function resolveLinmShellPublicUrl(): string {
  const configured = (import.meta.env.VITE_LINM_SHELL_PUBLIC_URL || '').trim();
  if (configured) return configured;

  const path = resolveLinmHomePath();
  if (typeof window !== 'undefined') {
    return `${window.location.origin}${path.startsWith('/') ? path : `/${path}`}`;
  }
  return path;
}

export function resolveLinmHomeLabel(): string {
  const label = (import.meta.env.VITE_LINM_HOME_LABEL || '').trim();
  return label || 'Home';
}
