import React, { useEffect } from 'react';
import { navigateToUrl } from 'single-spa';
import { isStandalone } from '../../dev/isStandalone';

export const AuthLoginRedirect: React.FC = () => {
  useEffect(() => {
    if (!isStandalone) {
      navigateToUrl('/login');
    }
  }, []);

  return null;
};
