import React, { useCallback, useEffect, useMemo, useState } from 'react';
import classNames from 'classnames';
import { useLocation, useNavigate } from 'react-router-dom';
import { linmLogo128 } from '@linm-soft-org/linm-web-common-components';
import { navigateInAppPath } from '../../router/navigateInAppPath';
import { resolveShellEmbedUrl } from '../../config/resolveShellEmbedUrl';
import {
  resolveLinmHomeLabel,
  resolveLinmHomePath,
} from '../../config/shellUrlConfig';
import styles from './ShellUrlHomePage.module.css';

const STORAGE_KEY = 'linm-home-collapsed';

function readCollapsed(): boolean {
  try {
    return sessionStorage.getItem(STORAGE_KEY) === '1';
  } catch {
    return false;
  }
}

function writeCollapsed(collapsed: boolean): void {
  try {
    sessionStorage.setItem(STORAGE_KEY, collapsed ? '1' : '0');
  } catch {
    /* ignore */
  }
}

/**
 * External content in iframe + FAB Home → in-shell path (giữ domain Linm).
 * Rule: external-app-linm-home — Home không full-navigate ra domain ngoài.
 */
const ShellUrlHomePage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const homePath = useMemo(() => resolveLinmHomePath(), []);
  const homeLabel = useMemo(() => resolveLinmHomeLabel(), []);
  const contentUrl = useMemo(
    () => resolveShellEmbedUrl(location.pathname),
    [location.pathname],
  );
  const [collapsed, setCollapsed] = useState(false);

  useEffect(() => {
    const timer = window.setTimeout(() => {
      setCollapsed(readCollapsed());
    }, 0);
    return () => window.clearTimeout(timer);
  }, []);

  const handleHome = useCallback(
    (e: React.MouseEvent<HTMLAnchorElement>) => {
      e.preventDefault();
      navigateInAppPath(homePath, navigate);
    },
    [homePath, navigate],
  );

  const handleMinimize = useCallback((e: React.MouseEvent<HTMLButtonElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setCollapsed((prev) => {
      const next = !prev;
      writeCollapsed(next);
      return next;
    });
    e.currentTarget.blur();
  }, []);

  return (
    <div className={styles.shellPage} data-testid="shell-url-home-page">
      {contentUrl ? (
        <iframe
          className={styles.contentFrame}
          data-testid="shell-url-content-frame"
          src={contentUrl}
          title="External application"
          sandbox="allow-same-origin allow-scripts allow-forms allow-popups allow-downloads"
        />
      ) : (
        <main className={styles.body}>
          <p className={styles.hint}>
            Chưa có menu <code>type=shell</code> khớp path <code>{location.pathname}</code>.
            Cấu hình tại Admin → Phân quyền &amp; cấu hình → Menu (path + DefaultUrl).
          </p>
        </main>
      )}

      <header
        className={classNames(styles.homeBar, collapsed && styles.homeBarCollapsed)}
        data-linm-home-bar
        aria-label="Platform navigation"
      >
        <div className={styles.homeFab}>
          <a
            className={styles.homeLink}
            data-linm-home-href
            data-testid="shell-url-home-btn"
            href={homePath}
            onClick={handleHome}
            aria-label={homeLabel}
            title={homeLabel}
          >
            <img
              className={styles.homeIcon}
              src={linmLogo128}
              width={44}
              height={44}
              alt=""
              aria-hidden
            />
          </a>
          <button
            type="button"
            className={styles.minimizeBtn}
            aria-label="Thu gọn nút Home"
            title="Thu gọn"
            data-testid="shell-url-home-minimize"
            onClick={handleMinimize}
          >
            ×
          </button>
        </div>
      </header>
    </div>
  );
};

export default ShellUrlHomePage;
