import React from 'react';
import { hasValidAuthToken } from '@linm-soft-org/linm-web-common-components';
import { isStandalone } from '../../dev/isStandalone';
import { AuthLoginRedirect } from './AuthLoginRedirect';

interface ProtectedRouteProps {
  children: React.ReactNode;
}

export const ProtectedRoute: React.FC<ProtectedRouteProps> = ({ children }) => {
  if (isStandalone) return <>{children}</>;
  if (!hasValidAuthToken()) return <AuthLoginRedirect />;
  return <>{children}</>;
};
