import React from 'react';
import singleSpaReact from 'single-spa-react';
import { createRoot } from 'react-dom/client';
import { installAuthFetchInterceptor } from '@linm-soft-org/linm-web-common-components';
import { patchResizeObserverLoopGuard } from './dev/patchResizeObserver';
import Root from './index';

patchResizeObserverLoopGuard();
installAuthFetchInterceptor();

const lifecycles = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: Root as any,
  errorBoundary(_error: Error, _info: React.ErrorInfo, _props: unknown) {
    return <div style={{ padding: 24, color: 'red' }}>Shell URL module failed to load.</div>;
  },
  renderType: 'createRoot',
});

export const { bootstrap, mount, unmount } = lifecycles;
