import { navigateToUrl } from 'single-spa';
import { isStandalone } from '../dev/isStandalone';

export type InAppNavigateFn = (to: string, options?: { replace?: boolean }) => void;

function normalizePath(path: string): string {
  const trimmed = (path || '').trim();
  if (!trimmed || trimmed === '#') return '/';
  const withSlash = trimmed.startsWith('/') ? trimmed : `/${trimmed}`;
  if (withSlash.length > 1 && withSlash.endsWith('/')) {
    return withSlash.slice(0, -1);
  }
  return withSlash;
}

export function navigateInAppPath(
  path: string,
  navigate: InAppNavigateFn,
  options?: { replace?: boolean },
): void {
  const normalized = normalizePath(path);
  if (isStandalone) {
    navigate(normalized, { replace: options?.replace });
    return;
  }
  navigateToUrl(normalized);
}

export { normalizePath };
